import uuid
import hashlib
import time
import json
from datetime import datetime
from concurrent import futures
from threading import Lock


class InMemoryStore:
    """Thread-safe in-memory data store simulating a database."""

    def __init__(self):
        self._users = {}
        self._tokens = {}
        self._user_data = {}
        self._lock = Lock()
        self._seed_data()

    def _hash_password(self, password):
        return hashlib.sha256(password.encode()).hexdigest()

    def _seed_data(self):
        """Seed with some initial data."""
        users = [
            ("alice", "alice@example.com", "password123"),
            ("bob", "bob@example.com", "password456"),
            ("charlie", "charlie@example.com", "password789"),
        ]
        for username, email, password in users:
            user_id = str(uuid.uuid4())
            self._users[user_id] = {
                "user_id": user_id,
                "username": username,
                "email": email,
                "password_hash": self._hash_password(password),
                "created_at": datetime.utcnow().isoformat(),
                "metadata": {"role": "user", "status": "active"},
            }
            self._user_data[user_id] = {
                "preferences": json.dumps({"theme": "dark", "language": "en"}),
                "profile": json.dumps({"bio": f"Hi, I'm {username}!", "avatar": f"/avatars/{username}.png"}),
                "settings": json.dumps({"notifications": True, "two_factor": False}),
                "activity_log": json.dumps({"last_login": datetime.utcnow().isoformat(), "login_count": 42}),
            }

    def register_user(self, username, email, password):
        with self._lock:
            for user in self._users.values():
                if user["username"] == username:
                    return None, "Username already exists"
                if user["email"] == email:
                    return None, "Email already registered"

            user_id = str(uuid.uuid4())
            self._users[user_id] = {
                "user_id": user_id,
                "username": username,
                "email": email,
                "password_hash": self._hash_password(password),
                "created_at": datetime.utcnow().isoformat(),
                "metadata": {"role": "user", "status": "active"},
            }
            self._user_data[user_id] = {}
            return user_id, "User registered successfully"

    def authenticate(self, username, password):
        with self._lock:
            for user in self._users.values():
                if user["username"] == username and user["password_hash"] == self._hash_password(password):
                    token = str(uuid.uuid4())
                    self._tokens[token] = {
                        "user_id": user["user_id"],
                        "username": user["username"],
                        "created_at": time.time(),
                    }
                    return token, user
            return None, None

    def validate_token(self, token):
        with self._lock:
            token_data = self._tokens.get(token)
            if token_data:
                # Token expires after 1 hour
                if time.time() - token_data["created_at"] < 3600:
                    return token_data
            return None

    def invalidate_token(self, token):
        with self._lock:
            if token in self._tokens:
                del self._tokens[token]
                return True
            return False

    def get_user(self, user_id):
        with self._lock:
            return self._users.get(user_id)

    def list_users(self, page=1, page_size=10):
        with self._lock:
            all_users = list(self._users.values())
            total = len(all_users)
            start = (page - 1) * page_size
            end = start + page_size
            return all_users[start:end], total

    def search_users(self, query, page=1, page_size=10):
        with self._lock:
            matching = [
                u for u in self._users.values()
                if query.lower() in u["username"].lower() or query.lower() in u["email"].lower()
            ]
            total = len(matching)
            start = (page - 1) * page_size
            end = start + page_size
            return matching[start:end], total

    def get_user_data(self, user_id, data_key):
        with self._lock:
            user_data = self._user_data.get(user_id, {})
            if data_key in user_data:
                return user_data[data_key]
            return None

    def get_all_user_data(self, user_id):
        with self._lock:
            return dict(self._user_data.get(user_id, {}))


# Global store instance
