class AuthServiceServicer(service_pb2_grpc.AuthServiceServicer):
    """Implementation of the Authentication gRPC service."""

    def Login(self, request, context):
        print(f"[AuthService] Login attempt for user: {request.username}")

        if not request.username or not request.password:
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details("Username and password are required")
            return service_pb2.LoginResponse(
                success=False,
                message="Username and password are required"
            )

        token, user = store.authenticate(request.username, request.password)

        if token and user:
            user_info = service_pb2.UserInfo(
                user_id=user["user_id"],
                username=user["username"],
                email=user["email"],
                created_at=user["created_at"],
                metadata=user.get("metadata", {}),
            )
            print(f"[AuthService] Login successful for user: {request.username}")
            return service_pb2.LoginResponse(
                success=True,
                token=token,
                message="Login successful",
                user=user_info,
            )
        else:
            print(f"[AuthService] Login failed for user: {request.username}")
            return service_pb2.LoginResponse(
                success=False,
                message="Invalid username or password"
            )

    def Register(self, request, context):
        print(f"[AuthService] Registration attempt for user: {request.username}")

        if not request.username or not request.email or not request.password:
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details("All fields are required")
            return service_pb2.RegisterResponse(
                success=False,
                message="Username, email, and password are required"
            )

        if len(request.password) < 6:
            return service_pb2.RegisterResponse(
                success=False,
                message="Password must be at least 6 characters"
            )

        user_id, message = store.register_user(
            request.username, request.email, request.password
        )

        if user_id:
            print(f"[AuthService] Registration successful: {request.username} ({user_id})")
            return service_pb2.RegisterResponse(
                success=True,
                message=message,
                user_id=user_id,
            )
        else:
            print(f"[AuthService] Registration failed: {message}")
            return service_pb2.RegisterResponse(
                success=False,
                message=message,
            )

    def ValidateToken(self, request, context):
        print(f"[AuthService] Token validation request")

        token_data = store.validate_token(request.token)

        if token_data:
            return service_pb2.ValidateTokenResponse(
                valid=True,
                user_id=token_data["user_id"],
                username=token_data["username"],
            )
        else:
            return service_pb2.ValidateTokenResponse(valid=False)

    def Logout(self, request, context):
        print(f"[AuthService] Logout request")

        success = store.invalidate_token(request.token)

        return service_pb2.LogoutResponse(
            success=success,
            message="Logged out successfully" if success else "Invalid token",
        )


